import React, { useState } from 'react';
import {
  Box,
  Typography,
  Card,
  CardContent,
  Avatar,
  IconButton,
  Divider,
  Paper,
  TextField,
  Button
} from '@mui/material';
import FormatQuoteIcon from '@mui/icons-material/FormatQuote';
import NavigateNextIcon from '@mui/icons-material/NavigateNext';
import NavigateBeforeIcon from '@mui/icons-material/NavigateBefore';
import ContentCopyIcon from '@mui/icons-material/ContentCopy';
import VerifiedIcon from '@mui/icons-material/Verified';

const TestimonialWidget = ({ testimonials, onCopy }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [copied, setCopied] = useState(false);

  const handleNext = () => {
    setCurrentIndex((prev) => (prev + 1) % testimonials.length);
  };

  const handlePrev = () => {
    setCurrentIndex((prev) => (prev - 1 + testimonials.length) % testimonials.length);
  };

  const embedCode = `<iframe src="https://testy.app/embed/${testimonials[currentIndex].id}" width="100%" height="300" frameborder="0"></iframe>`;

  const handleCopy = () => {
    navigator.clipboard.writeText(embedCode);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
    if (onCopy) onCopy();
  };

  return (
    <Box>
      <Box sx={{ mb: 4 }}>
        <Card 
          elevation={0}
          sx={{ 
            borderRadius: 3,
            border: '1px solid rgba(0, 0, 0, 0.08)',
            overflow: 'hidden',
            position: 'relative'
          }}
        >
          <CardContent sx={{ p: 4 }}>
            <Box sx={{ position: 'absolute', top: 16, right: 16 }}>
              <Box sx={{ display: 'flex', alignItems: 'center' }}>
                <VerifiedIcon sx={{ fontSize: 16, color: 'success.main', mr: 0.5 }} />
                <Typography variant="caption" color="success.main" sx={{ fontWeight: 600 }}>
                  Verified
                </Typography>
              </Box>
            </Box>

            <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
              <Avatar sx={{ mr: 2 }}>
                {testimonials[currentIndex].clientName.charAt(0)}
              </Avatar>
              <Box>
                <Typography variant="subtitle1" sx={{ fontWeight: 600 }}>
                  {testimonials[currentIndex].clientName}
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  {testimonials[currentIndex].clientCompany}
                </Typography>
              </Box>
            </Box>

            <Box sx={{ position: 'relative', mb: 2 }}>
              <FormatQuoteIcon 
                sx={{ 
                  position: 'absolute',
                  top: -10,
                  left: -5,
                  color: 'primary.main',
                  opacity: 0.2,
                  fontSize: 40,
                  transform: 'rotate(180deg)'
                }}
              />
              <Typography variant="body1" sx={{ pl: 4 }}>
                {testimonials[currentIndex].enhanced}
              </Typography>
            </Box>

            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <Box sx={{ display: 'flex' }}>
                <IconButton size="small" onClick={handlePrev}>
                  <NavigateBeforeIcon />
                </IconButton>
                <IconButton size="small" onClick={handleNext}>
                  <NavigateNextIcon />
                </IconButton>
              </Box>
              <Typography variant="caption" color="text.secondary">
                Powered by Testy
              </Typography>
            </Box>
          </CardContent>
        </Card>
      </Box>

      <Typography variant="subtitle2" gutterBottom>
        Embed this testimonial on your website
      </Typography>

      <Paper 
        elevation={0}
        sx={{ 
          p: 2,
          borderRadius: 2,
          border: '1px solid rgba(0, 0, 0, 0.08)',
          mb: 2
        }}
      >
        <Box sx={{ display: 'flex' }}>
          <TextField
            fullWidth
            variant="outlined"
            size="small"
            value={embedCode}
            InputProps={{
              readOnly: true,
            }}
          />
          <Button
            variant="contained"
            color={copied ? "success" : "primary"}
            startIcon={<ContentCopyIcon />}
            onClick={handleCopy}
            sx={{ ml: 1 }}
          >
            {copied ? "Copied!" : "Copy"}
          </Button>
        </Box>
      </Paper>

      <Typography variant="caption" color="text.secondary">
        This widget will automatically update when you add new testimonials.
      </Typography>
    </Box>
  );
};

export default TestimonialWidget;
